{
  "name": "CodeInsight AI",
  "description": "An intelligent coding assistant for Python, SQL, Excel, and PowerBI DAX. Features split-screen structured answers, code visualization, and simulated execution against a demo database."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum AppMode {
  SOLVER = 'SOLVER',
  GENERATOR = 'GENERATOR'
}

export enum SupportedLanguage {
  PYTHON = 'python',
  SQL = 'sql',
  DAX = 'dax',
  EXCEL = 'excel',
  UNKNOWN = 'text'
}

export interface ExecutionResult {
  outputType: 'text' | 'table' | 'error';
  content: string | string[][]; // Plain text or 2D array for tables
}

export interface AIResponse {
  explanation: string;
  code: string;
  language: SupportedLanguage;
  executionOutput: ExecutionResult;
  title: string;
}

export interface ChatMessage {
  id: string;
  role: 'user' | 'model';
  text?: string;
  image?: string; // Base64
  data?: AIResponse;
  timestamp: number;
}

import { GoogleGenAI, Type, Schema } from "@google/genai";
import { AppMode, AIResponse, SupportedLanguage } from "../types";

// Define the schema for the AI response to ensure structured data
const responseSchema: Schema = {
  type: Type.OBJECT,
  properties: {
    title: { type: Type.STRING, description: "A short, concise title for the solution or question." },
    explanation: { type: Type.STRING, description: "A detailed markdown explanation of the logic, concepts, and approach." },
    code: { type: Type.STRING, description: "The solution code or formula." },
    language: { 
      type: Type.STRING, 
      enum: [SupportedLanguage.PYTHON, SupportedLanguage.SQL, SupportedLanguage.DAX, SupportedLanguage.EXCEL, SupportedLanguage.UNKNOWN],
      description: "The programming language or tool used."
    },
    executionOutput: {
      type: Type.OBJECT,
      description: "The simulated output of running the code against a demo Retail/Sales database.",
      properties: {
        outputType: { 
          type: Type.STRING, 
          enum: ['text', 'table', 'error'],
          description: "Format of the output. Use 'table' for SQL/Dataframe results, 'text' for logs/scalar values."
        },
        content: {
          type: Type.STRING,
          description: "The actual output content. If outputType is table, provide a JSON string representing a 2D array (rows). If text, just the string."
        }
      },
      required: ["outputType", "content"]
    }
  },
  required: ["title", "explanation", "code", "language", "executionOutput"]
};

const SYSTEM_INSTRUCTION = `
You are CodeInsight, an expert AI coding assistant specializing in Data Analytics and Engineering. 
You are an expert in Python, SQL, PowerBI DAX, and Excel Formulas.

Your goal is to either SOLVE questions provided by the user OR GENERATE practice questions based on a topic.

CONTEXT:
Assume we are working with a standard "Demo Retail Database" (like AdventureWorks or Northwind) containing:
1. 'Sales' table (OrderID, Date, ProductID, CustomerID, Quantity, Amount)
2. 'Products' table (ProductID, ProductName, Category, UnitPrice)
3. 'Customers' table (CustomerID, CustomerName, Region, Segment)
4. 'Dates' table (Date, Month, Quarter, Year)

INSTRUCTIONS:
1. Provide a clear, educational explanation in Markdown.
2. Provide the exact code snippet.
3. SIMULATE the execution of this code against the Demo Database mentioned above. 
   - If it's SQL, show the resulting query table.
   - If it's Python, show the print output or DataFrame head.
   - If it's DAX, show the calculated measure value or table.
   - If it's Excel, show the cell result.
4. If the user asks for a "Question", generate a challenging interview-style question and provide the solution for it immediately in the same format.
`;

export const generateContent = async (
  prompt: string, 
  mode: AppMode, 
  imageBase64?: string
): Promise<AIResponse> => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) throw new Error("API_KEY is missing");

  const ai = new GoogleGenAI({ apiKey });

  let fullPrompt = prompt;
  if (mode === AppMode.GENERATOR) {
    fullPrompt = `Generate a challenging interview question and solution about: ${prompt}`;
  }

  const parts: any[] = [{ text: fullPrompt }];

  if (imageBase64) {
    parts.unshift({
      inlineData: {
        data: imageBase64,
        mimeType: 'image/png', // Assuming PNG for simplicity in this demo, typically would detect
      }
    });
  }

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: {
        parts: parts
      },
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        responseMimeType: "application/json",
        responseSchema: responseSchema,
      }
    });

    const text = response.text;
    if (!text) throw new Error("No response from AI");

    const parsed = JSON.parse(text);

    // Normalize table content if it comes as a stringified JSON
    let cleanContent = parsed.executionOutput.content;
    if (parsed.executionOutput.outputType === 'table' && typeof cleanContent === 'string') {
        try {
            // Sometimes the model double-encodes or just puts the raw string representation
            // We'll try to parse it if it looks like an array
            if (cleanContent.trim().startsWith('[')) {
                cleanContent = JSON.parse(cleanContent);
            }
        } catch (e) {
            console.warn("Failed to parse table content", e);
            // Fallback to text if parsing fails
            parsed.executionOutput.outputType = 'text'; 
        }
    }

    return {
      ...parsed,
      executionOutput: {
        ...parsed.executionOutput,
        content: cleanContent
      }
    };

  } catch (error) {
    console.error("Gemini API Error:", error);
    throw error;
  }
};

import React from 'react';
import { SupportedLanguage } from '../types';

interface CodeEditorProps {
  code: string;
  language: SupportedLanguage;
}

const CodeEditor: React.FC<CodeEditorProps> = ({ code, language }) => {
  const lines = code.split('\n');

  return (
    <div className="flex flex-col h-full bg-[#1e1e1e] text-[#d4d4d4] font-mono text-sm overflow-hidden rounded-md border border-[#333]">
      {/* Fake Tabs/Header */}
      <div className="flex items-center bg-[#252526] px-4 py-2 border-b border-[#1e1e1e]">
        <span className="text-xs uppercase tracking-wider font-semibold text-blue-400 mr-2">
          {language}
        </span>
        <span className="text-xs text-gray-500">main.{language === 'python' ? 'py' : language === 'sql' ? 'sql' : language === 'dax' ? 'dax' : 'txt'}</span>
      </div>

      <div className="flex flex-1 overflow-auto custom-scrollbar relative">
        {/* Line Numbers */}
        <div className="flex flex-col items-end px-2 py-4 bg-[#1e1e1e] border-r border-[#333] select-none text-[#858585] min-w-[3rem]">
          {lines.map((_, i) => (
            <div key={i} className="leading-6 h-6">{i + 1}</div>
          ))}
        </div>

        {/* Code Content */}
        <div className="flex-1 py-4 px-4 overflow-x-auto">
          {lines.map((line, i) => (
            <div key={i} className="leading-6 h-6 whitespace-pre">
              {/* Very basic manual highlighting for effect since we can't use heavy libs */}
              <CodeLine line={line} language={language} />
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

const CodeLine: React.FC<{ line: string; language: string }> = ({ line, language }) => {
  // Simple heuristic highlighting
  const keywords = ['SELECT', 'FROM', 'WHERE', 'GROUP BY', 'ORDER BY', 'def', 'import', 'return', 'print', 'CALCULATE', 'FILTER', 'ALL', 'SUM', 'AVERAGE', 'IF'];

  const parts = line.split(/(\s+|[(),.])/g); // Split by space or punctuation, keep delimiters

  return (
    <>
      {parts.map((part, index) => {
        if (keywords.includes(part.toUpperCase())) {
          return <span key={index} className="text-[#c586c0] font-bold">{part}</span>; // Purple
        } else if (part.startsWith('"') || part.startsWith("'") || part.endsWith('"') || part.endsWith("'")) {
          return <span key={index} className="text-[#ce9178]">{part}</span>; // Orange/String
        } else if (!isNaN(Number(part)) && part.trim() !== '') {
          return <span key={index} className="text-[#b5cea8]">{part}</span>; // Light Green/Number
        } else if (part.startsWith('#') || part.startsWith('--')) {
           return <span key={index} className="text-[#6a9955]">{part}</span>; // Comment Green (simplified, usually handles rest of line)
        }
        return <span key={index}>{part}</span>;
      })}
    </>
  );
};

export default CodeEditor;

import React from 'react';
import { ExecutionResult } from '../types';
import { Terminal, Table, AlertCircle } from 'lucide-react';

interface ExecutionWindowProps {
  result: ExecutionResult;
}

const ExecutionWindow: React.FC<ExecutionWindowProps> = ({ result }) => {
  const isTable = result.outputType === 'table' && Array.isArray(result.content);

  return (
    <div className="flex flex-col h-full bg-[#0f111a] border border-[#333] rounded-md overflow-hidden">
      {/* Header */}
      <div className="flex items-center px-4 py-2 bg-[#1a1c29] border-b border-[#333]">
        <div className="flex items-center gap-2 text-xs font-semibold text-gray-400">
          {isTable ? <Table size={14} /> : <Terminal size={14} />}
          <span>EXECUTION OUTPUT</span>
        </div>
        <div className="ml-auto flex items-center gap-2">
            <span className="w-2 h-2 rounded-full bg-green-500 animate-pulse"></span>
            <span className="text-[10px] text-green-500">Live Connection (Demo DB)</span>
        </div>
      </div>

      {/* Content */}
      <div className="flex-1 overflow-auto p-4 font-mono text-sm">
        {result.outputType === 'error' ? (
          <div className="text-red-400 flex items-start gap-2">
            <AlertCircle size={16} className="mt-0.5" />
            <pre className="whitespace-pre-wrap">{String(result.content)}</pre>
          </div>
        ) : isTable ? (
          <div className="overflow-x-auto">
            <table className="min-w-full text-left text-xs border-collapse">
              <thead>
                <tr>
                  {(result.content as string[])[0]?.map((header: string, i: number) => (
                    <th key={i} className="border-b border-[#333] py-2 px-3 text-gray-400 font-medium bg-[#1a1c29] whitespace-nowrap">
                      {header}
                    </th>
                  ))}
                </tr>
              </thead>
              <tbody>
                {(result.content as string[][]).slice(1).map((row, rowIndex) => (
                  <tr key={rowIndex} className="hover:bg-[#1a1c29] transition-colors">
                    {row.map((cell, cellIndex) => (
                      <td key={cellIndex} className="border-b border-[#2a2a2a] py-2 px-3 text-gray-300 whitespace-nowrap">
                        {cell}
                      </td>
                    ))}
                  </tr>
                ))}
              </tbody>
            </table>
            <div className="mt-2 text-xs text-gray-600 italic">
              Showing {(result.content as string[][]).length - 1} rows.
            </div>
          </div>
        ) : (
          <div className="text-gray-300 whitespace-pre-wrap">
            <span className="text-green-500 mr-2">➜</span>
            {String(result.content)}
          </div>
        )}
      </div>
    </div>
  );
};

export default ExecutionWindow;

import React, { useState, useRef, useEffect } from 'react';
import { Send, Upload, Cpu, Code2, Database, Zap, BookOpen, Trash2, Plus } from 'lucide-react';
import { generateContent } from './services/geminiService';
import { AppMode, ChatMessage, SupportedLanguage } from './types';
import CodeEditor from './components/CodeEditor';
import ExecutionWindow from './components/ExecutionWindow';
import ReactMarkdown from 'react-markdown';

const App: React.FC = () => {
  const [mode, setMode] = useState<AppMode>(AppMode.SOLVER);
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);
  const [activeMessageId, setActiveMessageId] = useState<string | null>(null);
  const [selectedImage, setSelectedImage] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  // Scroll to bottom of chat
  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  const handleSend = async () => {
    if ((!input.trim() && !selectedImage) || loading) return;

    const userMsg: ChatMessage = {
      id: Date.now().toString(),
      role: 'user',
      text: input,
      image: selectedImage || undefined,
      timestamp: Date.now()
    };

    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setSelectedImage(null);
    setLoading(true);

    try {
      const data = await generateContent(userMsg.text || "Analyze this image", mode, userMsg.image?.split(',')[1]);

      const aiMsg: ChatMessage = {
        id: (Date.now() + 1).toString(),
        role: 'model',
        data: data,
        timestamp: Date.now()
      };

      setMessages(prev => [...prev, aiMsg]);
      setActiveMessageId(aiMsg.id);
    } catch (error) {
      console.error(error);
      const errorMsg: ChatMessage = {
        id: (Date.now() + 1).toString(),
        role: 'model',
        text: "Sorry, I encountered an error processing your request. Please check your API key and try again.",
        timestamp: Date.now()
      };
      setMessages(prev => [...prev, errorMsg]);
    } finally {
      setLoading(false);
    }
  };

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setSelectedImage(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const handlePaste = (e: React.ClipboardEvent) => {
    const items = e.clipboardData.items;
    for (const item of items) {
      if (item.type.indexOf("image") !== -1) {
        e.preventDefault();
        const blob = item.getAsFile();
        const reader = new FileReader();
        reader.onload = (event) => {
          setSelectedImage(event.target?.result as string);
        };
        if (blob) reader.readAsDataURL(blob);
      }
    }
  };

  const activeMessage = messages.find(m => m.id === activeMessageId) || messages.filter(m => m.role === 'model').slice(-1)[0];

  return (
    <div className="flex h-screen bg-[#0f172a] text-white overflow-hidden font-sans">

      {/* Left Sidebar / Chat Area (40%) */}
      <div className="w-[40%] flex flex-col border-r border-gray-800 bg-[#111827] relative z-10 shadow-xl">
        {/* Header */}
        <div className="p-4 border-b border-gray-800 flex items-center justify-between bg-[#111827]/90 backdrop-blur">
          <div className="flex items-center gap-2">
            <div className="w-8 h-8 rounded-lg bg-indigo-600 flex items-center justify-center shadow-lg shadow-indigo-500/20">
              <Zap className="text-white" size={18} />
            </div>
            <h1 className="font-bold text-lg tracking-tight">CodeInsight</h1>
          </div>

          <div className="flex bg-gray-800 rounded-lg p-1">
            <button
              onClick={() => setMode(AppMode.SOLVER)}
              className={`px-3 py-1.5 rounded-md text-xs font-medium transition-all ${mode === AppMode.SOLVER ? 'bg-indigo-600 text-white shadow' : 'text-gray-400 hover:text-white'}`}
            >
              Solver
            </button>
            <button
              onClick={() => setMode(AppMode.GENERATOR)}
              className={`px-3 py-1.5 rounded-md text-xs font-medium transition-all ${mode === AppMode.GENERATOR ? 'bg-purple-600 text-white shadow' : 'text-gray-400 hover:text-white'}`}
            >
              Generator
            </button>
          </div>
        </div>

        {/* Messages List */}
        <div className="flex-1 overflow-y-auto p-4 space-y-6 custom-scrollbar">
          {messages.length === 0 && (
            <div className="flex flex-col items-center justify-center h-full text-gray-500 space-y-4 opacity-50">
              <Code2 size={48} />
              <p className="text-center text-sm max-w-xs">
                Paste a coding problem (Ctrl+V) or ask me to generate a SQL/Python question.
              </p>
            </div>
          )}

          {messages.map((msg) => (
            <div 
              key={msg.id} 
              className={`group flex flex-col gap-2 ${msg.role === 'user' ? 'items-end' : 'items-start'}`}
              onClick={() => msg.role === 'model' && setActiveMessageId(msg.id)}
            >
              <div 
                className={`max-w-[90%] p-4 rounded-2xl text-sm leading-relaxed shadow-sm cursor-pointer border transition-all 
                  ${msg.role === 'user' 
                    ? 'bg-indigo-600/10 border-indigo-500/30 text-indigo-100 rounded-tr-sm' 
                    : `bg-gray-800/50 border-gray-700 rounded-tl-sm hover:border-gray-600 ${activeMessageId === msg.id ? 'ring-1 ring-indigo-500 border-indigo-500/50' : ''}`
                  }`}
              >
                {/* User Image */}
                {msg.image && (
                  <img src={msg.image} alt="User upload" className="max-h-40 rounded-lg mb-3 border border-indigo-500/20" />
                )}

                {/* Content */}
                {msg.text && <p className="whitespace-pre-wrap">{msg.text}</p>}

                {/* AI Structured Content Preview */}
                {msg.data && (
                  <div className="space-y-3">
                    <div className="flex items-center gap-2 text-indigo-400 font-semibold">
                      <BookOpen size={16} />
                      <span>{msg.data.title}</span>
                    </div>
                    <div className="prose prose-invert prose-sm max-w-none text-gray-300">
                      <ReactMarkdown>{msg.data.explanation}</ReactMarkdown>
                    </div>
                    <div className="text-xs text-gray-500 mt-2 flex items-center gap-1">
                      Click to view code & execution
                    </div>
                  </div>
                )}
              </div>
              <span className="text-[10px] text-gray-600 px-1">{new Date(msg.timestamp).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}</span>
            </div>
          ))}

          {loading && (
            <div className="flex items-center gap-3 p-4 text-gray-400 animate-pulse">
              <div className="w-2 h-2 bg-indigo-500 rounded-full animate-bounce"></div>
              <div className="w-2 h-2 bg-indigo-500 rounded-full animate-bounce delay-75"></div>
              <div className="w-2 h-2 bg-indigo-500 rounded-full animate-bounce delay-150"></div>
              <span className="text-xs">Processing logic & simulating output...</span>
            </div>
          )}
          <div ref={messagesEndRef} />
        </div>

        {/* Input Area */}
        <div className="p-4 bg-[#111827] border-t border-gray-800 z-20">
          {selectedImage && (
            <div className="relative inline-block mb-2">
              <img src={selectedImage} alt="Preview" className="h-16 rounded border border-gray-600" />
              <button 
                onClick={() => setSelectedImage(null)}
                className="absolute -top-2 -right-2 bg-red-500 rounded-full p-1 text-white shadow-sm hover:bg-red-600"
              >
                <Trash2 size={10} />
              </button>
            </div>
          )}
          <div className="relative bg-gray-900 rounded-xl border border-gray-700 shadow-inner focus-within:ring-2 focus-within:ring-indigo-500/50 transition-all">
            <textarea
              value={input}
              onChange={(e) => setInput(e.target.value)}
              onKeyDown={(e) => {
                if (e.key === 'Enter' && !e.shiftKey) {
                  e.preventDefault();
                  handleSend();
                }
              }}
              onPaste={handlePaste}
              placeholder={mode === AppMode.SOLVER ? "Paste code, question, or Ctrl+V image..." : "Describe the topic for a new question..."}
              className="w-full bg-transparent text-sm text-gray-200 p-4 pr-12 min-h-[60px] max-h-[150px] resize-none focus:outline-none custom-scrollbar"
            />

            <div className="absolute bottom-2 right-2 flex items-center gap-1">
               <button 
                onClick={() => fileInputRef.current?.click()}
                className="p-2 text-gray-400 hover:text-indigo-400 hover:bg-gray-800 rounded-full transition-colors"
                title="Upload Image"
              >
                <Upload size={18} />
                <input 
                  type="file" 
                  ref={fileInputRef} 
                  className="hidden" 
                  accept="image/*" 
                  onChange={handleImageUpload} 
                />
              </button>
              <button 
                onClick={handleSend}
                disabled={loading || (!input.trim() && !selectedImage)}
                className="p-2 bg-indigo-600 text-white rounded-lg shadow-md hover:bg-indigo-500 disabled:opacity-50 disabled:cursor-not-allowed transition-all"
              >
                <Send size={16} />
              </button>
            </div>
          </div>
          <div className="mt-2 text-[10px] text-gray-500 flex justify-between px-1">
            <span>Supports: Python, SQL, DAX, Excel</span>
            <span>Use Ctrl+V to paste screenshots</span>
          </div>
        </div>
      </div>

      {/* Right Content / IDE (60%) */}
      <div className="flex-1 bg-[#0f111a] flex flex-col relative">
        {activeMessage && activeMessage.data ? (
          <div className="flex flex-col h-full p-4 gap-4">
             {/* Info Strip */}
             <div className="flex items-center justify-between text-gray-400 text-xs px-1">
                <div className="flex items-center gap-2">
                    <Database size={14} className="text-indigo-400" />
                    <span>Context: <span className="text-gray-200 font-medium">Retail Sales Demo DB</span></span>
                </div>
                <div className="flex items-center gap-4">
                    <div className="flex items-center gap-1">
                        <span className="w-2 h-2 bg-yellow-500 rounded-full"></span>
                        <span>Read Only</span>
                    </div>
                    <div className="flex items-center gap-1">
                        <Cpu size={14} />
                        <span>Simulated Execution</span>
                    </div>
                </div>
             </div>

             {/* Code Editor Area */}
             <div className="flex-1 min-h-0 flex flex-col gap-1">
                <label className="text-xs font-semibold text-gray-500 uppercase tracking-wider pl-1">Source Code</label>
                <CodeEditor code={activeMessage.data.code} language={activeMessage.data.language} />
             </div>

             {/* Execution Window Area */}
             <div className="h-[40%] min-h-[200px] flex flex-col gap-1">
                <label className="text-xs font-semibold text-gray-500 uppercase tracking-wider pl-1">Terminal / Output</label>
                <ExecutionWindow result={activeMessage.data.executionOutput} />
             </div>
          </div>
        ) : (
            <div className="flex flex-col items-center justify-center h-full text-gray-600 space-y-6">
                <div className="w-24 h-24 rounded-full bg-gray-800/50 flex items-center justify-center border border-gray-700 shadow-2xl">
                    <Code2 size={40} className="opacity-50" />
                </div>
                <div className="text-center space-y-2">
                    <h3 className="text-xl font-medium text-gray-300">Ready to Code</h3>
                    <p className="text-sm max-w-md mx-auto">
                        Select a conversation from the left or start a new query to see the code, logic, and simulated execution output here.
                    </p>
                </div>

                <div className="grid grid-cols-2 gap-4 mt-8 opacity-40">
                    <div className="p-4 border border-gray-700 rounded bg-[#151b2b]">
                        <div className="h-2 w-20 bg-gray-600 rounded mb-2"></div>
                        <div className="h-2 w-32 bg-gray-700 rounded"></div>
                    </div>
                    <div className="p-4 border border-gray-700 rounded bg-[#151b2b]">
                        <div className="h-2 w-20 bg-gray-600 rounded mb-2"></div>
                        <div className="h-2 w-32 bg-gray-700 rounded"></div>
                    </div>
                </div>
            </div>
        )}
      </div>

    </div>
  );
};

export default App;

import React from 'react';
import { ExecutionResult } from '../types';
import { Terminal, Table, AlertCircle } from 'lucide-react';

interface ExecutionWindowProps {
  result: ExecutionResult;
}

const ExecutionWindow: React.FC<ExecutionWindowProps> = ({ result }) => {
  const isTable = result.outputType === 'table' && Array.isArray(result.content);

  return (
    <div className="flex flex-col h-full bg-[#0f111a] border border-[#333] rounded-md overflow-hidden">
      {/* Header */}
      <div className="flex items-center px-4 py-2 bg-[#1a1c29] border-b border-[#333]">
        <div className="flex items-center gap-2 text-xs font-semibold text-gray-400">
          {isTable ? <Table size={14} /> : <Terminal size={14} />}
          <span>EXECUTION OUTPUT</span>
